UPDATE EMPLOYEE
SET EMPLOYEE_PWD = #{newPassword}
WHERE EMPLOYEE_ID = #{employeeId}

UPDATE EMPLOYEE
SET EMPLOYEE_PHONE = #{employeePhone},
    EMPLOYEE_EMAIL = #{employeeEmail}
WHERE EMPLOYEE_ID = #{employeeId}

UPDATE EMPLOYEE
SET EMPLOYEE_NAME = #{employeeName},
    DEPT_ID = #{deptId},
    POSITION_ID = #{positionId},
    EMPLOYEE_PHONE = #{employeePhone}
WHERE EMPLOYEE_ID = #{employeeId}

UPDATE EMPLOYEE
SET EMPLOYEE_STATUS = #{employeeStatus}
WHERE EMPLOYEE_ID = #{employeeId}
